update faq set 
	category = #{category}, 
	question = #{question},
	answer = #{answer},
	display_order = #{display_order}
where faq_id = #{faq_id}

UPDATE faq 


		display_order = display_order + 1
		WHERE display_order >= #{newOrder} AND display_order < #{oldOrder}


		display_order = display_order - 1
		WHERE display_order <= #{newOrder} AND display_order > #{oldOrder}
